CNOT_ERRORS = {
    (0, 1): 0.01,
    (1, 0): 0.015,
    (1, 2): 0.008,
    (2, 1): 0.012,
}

def select_direction(q0, q1):
    error_01 = CNOT_ERRORS.get((q0, q1), float('inf'))
    error_10 = CNOT_ERRORS.get((q1, q0), float('inf'))

    if error_01 <= error_10:
        return (q0, q1)
    else:
        return (q1, q0)

print(f"CX(0,1): {select_direction(0, 1)}")
print(f"CX(1,2): {select_direction(1, 2)}")

