exercises.solution:
class Pass:
    def run(self, gates):
        return gates

class UnrollH(Pass):
    def run(self, gates):
        result = []
        for name, qubit in gates:
            if name == 'H':
                result.extend([('RZ', qubit), ('SX', qubit), ('RZ', qubit)])
            else:
                result.append((name, qubit))
        return result

class CancelXX(Pass):
    def run(self, gates):
        result = []
        for gate in gates:
            if result and gate[0] == 'X' and result[-1] == gate:
                result.pop()
            else:
                result.append(gate)
        return result

class Pipeline:
    def __init__(self):
        self.passes = []

    def add(self, p):
        self.passes.append(p)
        return self

    def run(self, gates):
        current = gates
        for p in self.passes:
            current = p.run(current)
        return current

pipeline = Pipeline()
pipeline.add(UnrollH()).add(CancelXX())

gates = [('H', 0), ('X', 1), ('X', 1)]
result = pipeline.run(gates)
print(f"Result: {result}")
